import React, { useState, useEffect } from 'react';
import Logo from './Logo.png'; 

// BRAND COLORS
const gold = '#D4AF37'; 
const terracotta = '#C04000'; 
const softCream = '#FDF5E6'; 

function App() {
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [currentSlide, setCurrentSlide] = useState(0);
  const [cart, setCart] = useState([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [showBankDetails, setShowBankDetails] = useState(false);
  const [isClockedIn, setIsClockedIn] = useState(false);

  const whatsappNumber = "2349122731172";
  const bankInfo = { bank: "PREMIUMTRUST BANK", account: "0112326977", name: "OLUKOYA OMOTOYOSI" };

  const slides = [
    { title: "EVERY BITE WORTH IT!", subtitle: "Lagos' favorite grills & small chops.", bgImage: "/images/chops_bg.jpg" },
    { title: "MADE FOR REAL CRAVINGS", subtitle: "Don't overthink it... just eat!", bgImage: "/images/wigs_bg.jpg" },
    { title: "PREMIUM TASTE, 9JA FLAVOR", subtitle: "The perfect balance of comfort.", bgImage: "/images/lunch_bg.jpg" }
  ];

  const menuData = {
    CHOPS: [
      { id: 1, name: "The Starter Pack", price: "15,000", desc: "7 Samosas, 7 Springrolls, 15 Puff-puff, 10 Mosa, 4 Grilled Chicken.", img: "/images/starter.jpg" },
      { id: 2, name: "The Signature Platter", price: "25,000", desc: "10 Samosas, 10 Springrolls, 25 Puff-puff, 20 Mosa, 8 Grilled Chicken.", img: "/images/signature.jpg" },
      { id: 3, name: "The Owambe Special", price: "150,000", desc: "Full event catering for 50 people.", img: "/images/owambe.jpg" },
      { id: 4, name: "The Customized Package", price: "200,000", desc: "Bespoke menu for 60 people and above.", img: "/images/custom.jpg", isCustom: true }
    ],
    LUNCH: [
      { day: "Monday", meal: "Smoky Jollof, Grilled Chicken & Salad" },
      { day: "Tuesday", meal: "Creamy Pasta, Sauteed Prawns & Garlic Bread" },
      { day: "Wednesday", meal: "Native Rice, Shredded Beef & Fried Plantain" },
      { day: "Thursday", meal: "Stir-fry Noodles, Teriyaki Wings & Veggies" },
      { day: "Friday", meal: "Chef's Special Surprise (TGIF Menu)" }
    ],
    WIGS: [
      { type: "Human Hair", items: [
          { id: 201, name: "Raw Cambodian", price: "85,000", desc: "14\" Frontal Unit", img: "/images/hair1.jpg" },
          { id: 202, name: "Bone Straight", price: "120,000", desc: "12\" Double Drawn", img: "/images/hair2.jpg" }
      ]},
      { type: "Premium Fibre", items: [
          { id: 203, name: "Sleek Straight", price: "35,000", desc: "Heat Resistant", img: "/images/hair3.jpg" },
          { id: 204, name: "Deep Wave", price: "38,000", desc: "Pre-styled", img: "/images/hair4.jpg" }
      ]}
    ]
  };

  useEffect(() => {
    const timer = setInterval(() => setCurrentSlide((s) => (s + 1) % slides.length), 5000);
    return () => clearInterval(timer);
  }, [slides.length]);

  const addToCart = (item) => setCart([...cart, item]);
  const total = cart.reduce((acc, item) => acc + parseInt(item.price.replace(/,/g, '')), 0);

  return (
    <div style={{ backgroundColor: '#fff', minHeight: '100vh', color: '#333', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* 1. TOP NAV */}
      <header style={{ padding: '15px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', backgroundColor: '#fff', position: 'sticky', top: 0, zIndex: 1000 }}>
        <img src={Logo} alt="Logo" style={{ height: '50px' }} />
        <div onClick={() => setIsCartOpen(true)} style={{ backgroundColor: '#000', color: '#fff', padding: '8px 18px', borderRadius: '20px', display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer' }}>
          🛒 <strong>{cart.length}</strong>
        </div>
      </header>

      {/* 2. HORIZONTAL SLIDER (PAPASGRILL STYLE) */}
      <div style={{ padding: '0 0 20px 0', overflow: 'hidden' }}>
        <div style={{ height: '200px', position: 'relative', backgroundColor: terracotta }}>
          {slides.map((slide, index) => (
            <div key={index} style={{ 
              position: 'absolute', width: '100%', height: '100%', 
              display: 'flex', alignItems: 'center', 
              opacity: index === currentSlide ? 1 : 0, 
              transition: 'opacity 0.8s ease-in-out',
              padding: '0 20px'
            }}>
              {/* TEXT SIDE */}
              <div style={{ flex: 1, color: '#fff', zIndex: 2 }}>
                <h2 style={{ fontSize: '1.4rem', fontWeight: '900', margin: 0, lineHeight: 1.2 }}>{slide.title}</h2>
                <p style={{ fontSize: '0.85rem', margin: '8px 0 0', opacity: 0.9 }}>{slide.subtitle}</p>
              </div>
              
              {/* IMAGE SIDE (HORIZONTAL/CROP) */}
              <div style={{ width: '45%', height: '160px', borderRadius: '12px', overflow: 'hidden', boxShadow: '0 10px 20px rgba(0,0,0,0.2)' }}>
                <img 
                  src={process.env.PUBLIC_URL + slide.bgImage} 
                  style={{ width: '100%', height: '100%', objectFit: 'cover' }} 
                  alt="" 
                />
              </div>
            </div>
          ))}
          
          {/* SLIDE INDICATORS (DOTS) */}
          <div style={{ position: 'absolute', bottom: '15px', left: '20px', display: 'flex', gap: '5px' }}>
            {slides.map((_, i) => (
              <div key={i} style={{ width: '8px', height: '8px', borderRadius: '50%', backgroundColor: i === currentSlide ? '#fff' : 'rgba(255,255,255,0.4)' }}></div>
            ))}
          </div>
        </div>
      </div>

      {/* 3. BUSINESS INFO */}
      <div style={{ padding: '0 20px 20px' }}>
        <h3 style={{ margin: 0, fontSize: '1.4rem' }}>AyoTech-Hub — Ikeja</h3>
        <p style={{ color: '#666', fontSize: '0.9rem', margin: '5px 0' }}>📍 Lagos, Nigeria</p>
        <div style={{ display: 'flex', gap: '10px', marginTop: '10px' }}>
            <button style={{ flex: 1, padding: '12px', borderRadius: '8px', border: '1px solid #ddd', backgroundColor: '#fff', fontWeight: '600' }}>Pickup</button>
            <button style={{ flex: 1, padding: '12px', borderRadius: '8px', border: 'none', backgroundColor: '#f5f5f5', color: '#999', fontWeight: '600' }}>Delivery</button>
        </div>
      </div>

      {/* 4. NAV TABS */}
      <div style={{ display: 'flex', gap: '10px', overflowX: 'auto', padding: '10px 20px', borderBottom: '1px solid #eee', scrollbarWidth: 'none' }}>
        {['Small Chops', 'Office Lunch', 'Wigs'].map((item) => (
          <button key={item} onClick={() => setActiveCategory(item)} style={{ whiteSpace: 'nowrap', padding: '10px 20px', borderRadius: '20px', border: 'none', backgroundColor: activeCategory === item ? '#000' : '#f5f5f5', color: activeCategory === item ? '#fff' : '#000', fontWeight: '700' }}>
            {item}
          </button>
        ))}
      </div>

      {/* 5. PRODUCT LIST */}
      <main style={{ padding: '20px 0 120px' }}>
        {activeCategory === 'Small Chops' && menuData.CHOPS.map((item) => (
          <div key={item.id} style={{ display: 'flex', padding: '15px 20px', borderBottom: '1px solid #f9f9f9', alignItems: 'center' }}>
            <div style={{ flex: 1, paddingRight: '15px' }}>
              <h4 style={{ margin: 0, fontSize: '1rem' }}>{item.name}</h4>
              <p style={{ fontSize: '0.8rem', color: '#777', margin: '4px 0' }}>{item.desc}</p>
              <div style={{ fontWeight: 'bold', marginTop: '5px' }}>₦{item.price}</div>
            </div>
            <div style={{ width: '80px', height: '80px', borderRadius: '10px', overflow: 'hidden', position: 'relative' }}>
              <img src={item.img} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
              <button 
                onClick={() => item.isCustom ? window.open(`https://wa.me/${whatsappNumber}`) : addToCart(item)}
                style={{ position: 'absolute', bottom: '5px', right: '5px', backgroundColor: '#fff', border: '1px solid #ddd', borderRadius: '5px', padding: '2px 8px', fontWeight: 'bold', fontSize: '0.7rem' }}
              >
                {item.isCustom ? 'BOOK' : '+ ADD'}
              </button>
            </div>
          </div>
        ))}
        {/* Lunch and Wigs follow same style... */}
      </main>

      {/* 6. FOOTER CART */}
      {cart.length > 0 && (
        <div style={{ position: 'fixed', bottom: 0, width: '100%', padding: '20px', backgroundColor: '#fff', borderTop: '1px solid #eee', zIndex: 1001 }}>
          <button onClick={() => setIsCartOpen(true)} style={{ width: '100%', backgroundColor: terracotta, color: '#fff', padding: '16px', borderRadius: '12px', border: 'none', fontWeight: 'bold', display: 'flex', justifyContent: 'space-between' }}>
            <span>View Cart ({cart.length})</span>
            <span>₦{total.toLocaleString()}</span>
          </button>
        </div>
      )}
    </div>
  );
}

export default App;
